import sys

def main():
    n, k = map(int, sys.stdin.readline().split())
    a = [0] * n
    for i in range(n):
        and_val = -1
        or_val = -1
        for j in range(n):
            if i == j:
                continue
            print(f"and {i+1} {j+1}")
            sys.stdout.flush()
            res = int(sys.stdin.readline())
            if res == -1:
                return
            if and_val == -1:
                and_val = res
            else:
                and_val &= res
            print(f"or {i+1} {j+1}")
            sys.stdout.flush()
            res = int(sys.stdin.readline())
            if res == -1:
                return
            if or_val == -1:
                or_val = res
            else:
                or_val |= res
        a[i] = and_val | or_val
    a_sorted = sorted(a)
    print(f"finish {a_sorted[k-1]}")
    sys.stdout.flush()

if __name__ == "__main__":
    main()

